phase1.code:
fun main() {
    // ---- Basic when ----
    val day = 3
    val dayName = when (day) {
        1 -> "Monday"
        2 -> "Tuesday"
        3 -> "Wednesday"
        4 -> "Thursday"
        5 -> "Friday"
        6 -> "Saturday"
        7 -> "Sunday"
        else -> "Invalid day"
    }
    println("Day $day: $dayName")

    // ---- when with ranges ----
    val score = 85
    val grade = when (score) {
        in 90..100 -> "A"
        in 80..89 -> "B"
        in 70..79 -> "C"
        in 60..69 -> "D"
        else -> "F"
    }
    println("Score $score: $grade")

    // ---- when without argument ----
    val age = 25
    val status = when {
        age < 18 -> "Minor"
        age in 18..64 -> "Adult"
        else -> "Senior"
    }
    println("Age $age: $status")

    // ---- when as expression ----
    val isEven = when (42 % 2) {
        0 -> "even"
        else -> "odd"
    }
    println("42 is $isEven")

    // ---- when with multiple conditions ----
    val x = 5
    val description = when (x) {
        0, 1 -> "Small"
        2, 3, 4 -> "Medium"
        5, 6, 7 -> "Large"
        else -> "Too big"
    }
    println("$x: $description")

    // ---- when with any type ----
    val obj: Any = "Hello"
    val type = when (obj) {
        is String -> "String: ${obj.length} chars"
        is Int -> "Int: $obj"
        is Boolean -> "Boolean: $obj"
        else -> "Unknown type"
    }
    println(type)

    // ---- when with smart casting ----
    fun printType(obj: Any) = when (obj) {
        is String -> println("String length: ${obj.length}")
        is Int -> println("Int value: $obj")
        is List<*> -> println("List size: ${obj.size}")
        else -> println("Unknown")
    }
    printType("Hello")
    printType(42)
    printType(listOf(1, 2, 3))

    // ---- when as a statement ----
    when (day) {
        1, 2, 3, 4, 5 -> println("Weekday")
        6, 7 -> println("Weekend")
        else -> println("Invalid")
    }
}

